247→        private void Control2Arry()
248→        {
249→            Graph = BindControlsByIndex<ZedGraphControl>(this, "Graph", 7);
250→            SpecStartUp = BindControlsByIndex<System.Windows.Forms.Label>(this, "Spec_StartUp", 4);
251→            SpecOperating = BindControlsByIndex<System.Windows.Forms.Label>(this, "Spec_Operating", 4);
252→            ValStartUp = BindControlsByIndex<System.Windows.Forms.Label>(this, "Val_StartUp", 4);
253→            ValOperating = BindControlsByIndex<System.Windows.Forms.Label>(this, "Val_Operating", 4);
254→            DecStartUp = BindControlsByIndex<System.Windows.Forms.Label>(this, "Dec_StartUp", 4);
255→            DecOperating = BindControlsByIndex<System.Windows.Forms.Label>(this, "Dec_Operating", 4);
