258→        private static T[] BindControlsByIndex<T>(Control root, string baseName, int count)
259→        where T : Control
260→        {
261→            var arr = new T[count];
262→            for (int i = 1; i <= count; i++)
263→            {
264→                string name = $"{baseName}{i}";
265→                // true: 모든 자식 컨테이너까지 검색
266→                var found = root.Controls.Find(name, true).FirstOrDefault() as T;
267→                if (found == null)
268→                {
269→                    // 필요시 예외 대신 경고 로그/무시로 바꿔도 됨
270→                    throw new InvalidOperationException($"컨트롤을 찾을 수 없습니다: {name} (타입 {typeof(T).Name})");
271→                }
272→                arr[i - 1] = found;
273→            }
274→            return arr;
275→        }
