422→        /// </summary>
423→        private void AdjustListViewColumns(ListView list)
424→        {
425→            if (list == null || list.Columns.Count < 3) return;
426→
427→            int totalWidth = list.ClientSize.Width > 0 ? list.ClientSize.Width : 450; // 패널 크기 기준
428→            if (totalWidth <= 0) return;
429→
430→            // 비율로 컬럼 폭 설정 (스크롤바 여백 고려)
431→            list.Columns[0].Width = (int)(totalWidth * 0.35); // Band: 35%
432→            list.Columns[1].Width = (int)(totalWidth * 0.40); // RMS MAX: 40%
433→            list.Columns[2].Width = totalWidth - list.Columns[0].Width - list.Columns[1].Width - 5; // 판정: 나머지
434→        }
