478→        private void EnsureWriter(DateTime now)
479→        {
480→            if (_logSw == null || now.Date != _logDate)
481→            {
482→                try { _logSw?.Flush(); _logSw?.Dispose(); } catch (Exception ex) { System.Diagnostics.Debug.WriteLine($"[LOG] EnsureWriter StreamWriter 종료 중 예외: {ex.Message}"); }
483→                _logDate = now.Date;
