490→        private void LogWriterLoop(CancellationToken ct)
491→        {
492→            var lastFlush = DateTime.UtcNow;
493→            try
494→            {
495→                while (!ct.IsCancellationRequested || _logQueue.Count > 0)
496→                {
497→                    string line;
498→                    if (_logQueue.TryTake(out line, 250))
499→                    {
500→                        var now = DateTime.Now;

500→                        var now = DateTime.Now;
501→                        EnsureWriter(now);
502→                        _logSw.WriteLine(line);
503→                    }
504→
505→                    // 주기적 flush(0.5초마다)
506→                    if (_logSw != null && (DateTime.UtcNow - lastFlush).TotalMilliseconds > 500)
507→                    {
508→                        _logSw.Flush();
509→                        lastFlush = DateTime.UtcNow;
510→                    }
511→                }
512→            }
513→            catch (Exception ex)
514→            {
515→                System.Diagnostics.Debug.WriteLine("[LOG LOOP FAIL] " + ex);
516→            }
517→            finally
518→            {
519→                try { _logSw?.Flush(); _logSw?.Dispose(); } catch (Exception ex) { System.Diagnostics.Debug.WriteLine($"[LOG] EnsureWriter StreamWriter 종료 중 예외: {ex.Message}"); }
520→            }
521→        }
