637→        private void DaqFftSampler_DataAvailable(double[][] data)
638→        {
639→            try
640→            {
641→                if (data == null || data.Length == 0) return;
642→
643→                int chCount = data.Length;
644→                var statsArr = new FftFeatureCalculator.BasicStats[chCount];
645→                var bandArr = new FftFeatureCalculator.BandMetric[chCount][];
646→                var channelNames = FftConfig.IncludeNoise ? new[] { "Noise", "X", "Y", "Z" } : new[] { "X", "Y", "Z" };
647→
648→                var spectrumArr = new FftConfig.SpectrumData[chCount];
649→
650→                for (int ch = 0; ch < chCount; ch++)
651→                {
652→                    var samples = data[ch];
653→                    statsArr[ch] = FftFeatureCalculator.ComputeBasicStats(samples);
654→
655→                    // 소음 채널(첫 번째 채널, IncludeNoise일 때)의 실시간 값 계산
656→                    // 선형 전압-소음 변환기: 전압 평균 * 100 = dB
657→                    if (FftConfig.IncludeNoise && ch == 0)
658→                    {
659→                        double sum = 0.0;
660→                        int n = samples.Length;
661→                        if (n > 0)
662→                        {
663→                            for (int i = 0; i < n; i++)
664→                                sum += samples[i];
665→                            double vAvg = sum / n;
666→                            _currentNoiseValue = vAvg * 100.0; // dB 변환
667→                            ValueNoise = _currentNoiseValue; // 기존 필드에도 할당
668→                        }
669→                    }
670→
671→                    double[] freq, mag;
672→                    FftFeatureCalculator.ComputeSpectrum(samples, FftConfig.SampleRateHz, out freq, out mag);
673→
674→                    // 스펙트럼 데이터 저장
675→                    spectrumArr[ch] = new FftConfig.SpectrumData { Freq = freq, Mag = mag };
676→
677→                    var bandRanges = FftConfig.Bands;
678→                    var bands = new FftFeatureCalculator.BandMetric[bandRanges.Count];
679→                    for (int b = 0; b < bandRanges.Count; b++)
680→                    {
681→                        var band = bandRanges[b];
682→                        bands[b] = FftFeatureCalculator.ComputeBandMetric(freq, mag, band.StartHz, band.EndHz);
683→                    }
684→                    bandArr[ch] = bands;
685→                }
686→
687→                _lastDaqStats = statsArr;
688→                _lastDaqBands = bandArr;
689→                EvaluateFftDecision(statsArr, bandArr, channelNames, spectrumArr);
690→            }
691→            catch (Exception ex)
692→            {
693→                AppendLog("[ERR] FFT DAQ proc: " + ex.Message);
694→            }
695→        }
