717→        private void EvaluateFftDecision(FftFeatureCalculator.BasicStats[] stats, FftFeatureCalculator.BandMetric[][] bands, string[] channelNames, FftConfig.SpectrumData[] spectrums = null)
718→        {
719→            bool ok = true;
720→            string message = "OK";
721→            var thresholds = FftConfig.Thresholds;
722→            var bandDefs = FftConfig.Bands;
723→
724→            for (int ch = 0; ch < bands.Length; ch++)
725→            {
726→                var bmArr = bands[ch];
727→                for (int b = 0; b < bmArr.Length; b++)
728→                {
729→                    var th = (thresholds != null && b < thresholds.Count) ? thresholds[b] : null;
730→                    if (th == null) continue;
731→                    var bm = bmArr[b];
732→                    if (th.MaxRms > 0 && bm.Rms > th.MaxRms)
733→                    {
734→                        ok = false;
735→                        string bandText = (bandDefs != null && b < bandDefs.Count)
736→                            ? $"{bandDefs[b].StartHz}-{bandDefs[b].EndHz}Hz"
737→                            : $"Band {b}";
738→                        message = $"{channelNames[ch]} {bandText} RMS {bm.Rms:0.###} > {th.MaxRms:0.###}";
739→                        goto END_CHECK;
740→                    }
741→                    if (th.MaxPeak > 0 && bm.Peak > th.MaxPeak)
742→                    {
743→                        ok = false;
744→                        string bandText = (bandDefs != null && b < bandDefs.Count)
745→                            ? $"{bandDefs[b].StartHz}-{bandDefs[b].EndHz}Hz"
746→                            : $"Band {b}";
747→                        message = $"{channelNames[ch]} {bandText} Peak {bm.Peak:0.###} > {th.MaxPeak:0.###}";
748→                        goto END_CHECK;
749→                    }
750→                }
751→            }
752→
753→        END_CHECK:
754→            FftConfig.SetLastResult(new FftConfig.LastResult
755→            {
756→                Stats = stats,
757→                Bands = bands,
758→                DecisionOk = ok,
759→                DecisionMessage = message,
760→                Timestamp = DateTime.Now,
761→                Channels = channelNames,
762→                Spectrums = spectrums
763→            });
764→
765→            if (!ok)
766→            {
767→                vAppendLog("[FFT NG] " + message);
768→            }
769→
770→            UpdateFftStatusLabel(ok, message);
771→        }
