804→        private void SaveVibrationCsv(List<Sample> xSamples, List<Sample> ySamples, List<Sample> zSamples)
805→        {
806→            try
807→            {
808→                if (xSamples == null || ySamples == null || zSamples == null) return;
809→
810→                DateTime now = DateTime.Now;
811→                string dir = Path.Combine(AppDomain.CurrentDomain.BaseDirectory,
812→                    now.ToString("yyyy"),
813→                    now.ToString("MM"),
814→                    now.ToString("dd"));
815→                Directory.CreateDirectory(dir);
816→                string filePath = Path.Combine(dir, now.ToString("HHmmss") + ".csv");
817→
818→                // 샘플 간격 추정(FFT 참고용)
819→                double estFsX = EstimateSampleRate(xSamples);
820→                double estFsY = EstimateSampleRate(ySamples);
821→                double estFsZ = EstimateSampleRate(zSamples);
822→                double estFs = Math.Max(estFsX, Math.Max(estFsY, estFsZ));
823→
824→                var sb = new StringBuilder();
825→                sb.AppendLine("# Vib raw CSV");
826→                sb.AppendLine("# StartTime=" + now.ToString("yyyy-MM-dd HH:mm:ss"));
827→                sb.AppendLine("# Samples_X=" + xSamples.Count);
828→                sb.AppendLine("# Samples_Y=" + ySamples.Count);
829→                sb.AppendLine("# Samples_Z=" + zSamples.Count);
830→                sb.AppendLine("# EstFsX_Hz=" + estFsX.ToString("0.###", System.Globalization.CultureInfo.InvariantCulture));
831→                sb.AppendLine("# EstFsY_Hz=" + estFsY.ToString("0.###", System.Globalization.CultureInfo.InvariantCulture));
832→                sb.AppendLine("# EstFsZ_Hz=" + estFsZ.ToString("0.###", System.Globalization.CultureInfo.InvariantCulture));
833→                sb.AppendLine("# EstFsMax_Hz=" + estFs.ToString("0.###", System.Globalization.CultureInfo.InvariantCulture));
834→                sb.AppendLine("Index,Time(s),X(m/s^2),Y(m/s^2),Z(m/s^2)");
835→
836→                int maxCount = Math.Max(xSamples.Count, Math.Max(ySamples.Count, zSamples.Count));
837→                for (int i = 0; i < maxCount; i++)
838→                {
839→                    double tx = i < xSamples.Count ? xSamples[i].t : double.NaN;
840→                    double ty = i < ySamples.Count ? ySamples[i].t : double.NaN;
841→                    double tz = i < zSamples.Count ? zSamples[i].t : double.NaN;
842→                    double tRef = !double.IsNaN(tx) ? tx : (!double.IsNaN(ty) ? ty : tz);
843→                    double vx = i < xSamples.Count ? xSamples[i].v : double.NaN;
844→                    double vy = i < ySamples.Count ? ySamples[i].v : double.NaN;
845→                    double vz = i < zSamples.Count ? zSamples[i].v : double.NaN;
846→                    sb.AppendFormat(System.Globalization.CultureInfo.InvariantCulture,
847→                        "{0},{1},{2},{3},{4}\n", i, tRef, vx, vy, vz);
848→                }
849→
850→                File.WriteAllText(filePath, sb.ToString(), Encoding.ASCII);
851→                vAppendLog($"Vib CSV saved: {filePath}");
852→            }
853→            catch (Exception ex)
854→            {
855→                vAppendLog("[ERR] Save vib CSV: " + ex.Message);
856→            }
857→        }
858→
859→        private double EstimateSampleRate(List<Sample> samples)
860→        {
861→            if (samples == null || samples.Count < 2) return 0;
862→            var deltas = new List<double>(samples.Count - 1);
863→            for (int i = 1; i < samples.Count; i++)
864→            {
865→                double dt = samples[i].t - samples[i - 1].t;
866→                if (dt > 0) deltas.Add(dt);
867→            }
868→            if (deltas.Count == 0) return 0;
869→            deltas.Sort();
870→            double medianDt = deltas[deltas.Count / 2];
871→            return medianDt > 0 ? 1.0 / medianDt : 0;
872→        }
