1582→        private static string MidString(string s, int start1Based, int length)
1583→        {
1584→            if (string.IsNullOrEmpty(s) || length <= 0) return string.Empty;
1585→            int start = Math.Max(0, start1Based - 1);
1586→            if (start >= s.Length) return string.Empty;
1587→            if (start + length > s.Length) length = s.Length - start;
1588→            return s.Substring(start, length);
1589→        }
1590→        private string Asc2PrintStr(string str)
1591→        {
1592→            if (string.IsNullOrEmpty(str) || str.Length <= 2)
1593→                return string.Empty;
1594→
1595→            const string RS = "_1e";
1596→            const string GS = "_1d";
1597→            const string EOT = "_04";
1598→            var sb = new StringBuilder(str.Length * 2);
1599→            foreach (char ch in str)
1600→            {
1601→                int code = ch;
1602→                switch (code)
1603→                {
1604→                    case 4: sb.Append(EOT); break;
1605→                    case 30: sb.Append(RS); break;
1606→                    case 29: sb.Append(GS); break;
1607→                    default: sb.Append(ch); break;
1608→                }
1609→            }
1610→            if (sb.Length == 0)
1611→                return string.Empty;
1612→
1613→            return "#" + sb.ToString();
1614→        }
