1951→        public void InitPartsStore()
1952→        {
1953→            var accdbPath = Path.Combine(AppDomain.CurrentDomain.BaseDirectory, @"DB\DataBase_Setting.accdb");
1954→            _partsConnStr = $"Provider=Microsoft.ACE.OLEDB.12.0;Data Source={accdbPath}";
1955→
1956→            if (!File.Exists(accdbPath))
