1963→            int rows = LoadPartsTable();
1964→            AppendLog($"[DB] Table_Part loaded. rows={rows}");
1965→        }
1966→        private int LoadPartsTable()
1967→        {
1968→            var dt = new DataTable();
1969→
1970→            using (var adp = new OleDbDataAdapter(
1971→                "SELECT ID,TestID,BarcodeID,PartNo,PartName,CarType,Target_SW_Ver,Target_HW_Ver,ScanTarget,ControlType " +
1972→                "FROM Table_Part ORDER BY PartNo ASC",
1973→                _partsConnStr))
1974→            {
1975→                adp.MissingSchemaAction = MissingSchemaAction.Add;
1976→                int rows = adp.Fill(dt);
1977→                _partsTable = dt;
1978→                return rows;
1979→            }
1980→        }
