private static T[] BindControlsByIndex<T>(Control root, string baseName, int count, int startIndex = 1)
where T : Control
{
    var arr = new T[count];
    for (int i = 0; i < count; i++)
    {
        string name = $"{baseName}{startIndex + i}";
        // true: 모든 자식 컨테이너까지 검색
        var found = root.Controls.Find(name, true).FirstOrDefault() as T;
        if (found == null)
        {
            // 필요시 예외 대신 경고 로그/무시로 바꿔도 됨
            throw new InvalidOperationException($"컨트롤을 찾을 수 없습니다: {name} (타입 {typeof(T).Name})");
        }
        arr[i] = found;
    }
    return arr;
}

